using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public bool PurchaseItem(int price)
    {
        if (currency >= price)
        {
            currency -= price;
            return true;
        }
        return false;
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public void BuyHealthPotion()
    {
        int price = 10;
        if (playerStats.PurchaseItem(price))
        {
            playerStats.health += 20;
            if (playerStats.health > 100) playerStats.health = 100;
            Debug.Log("Purchased Health Potion!");
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }

    public void BuyWeaponUpgrade()
    {
        int price = 50;
        if (playerStats.PurchaseItem(price))
        {
            // Implement weapon upgrade effect
            Debug.Log("Purchased Weapon Upgrade!");
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }
}

